import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;

public class XSSSecureCode {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Attack!')</script>";

        HTMLEntityCodec codec = new HTMLEntityCodec();
        String encodedUserInput = codec.encodeForHTML(userInput);

        PrintWriter out = new PrintWriter(new FileWriter("output.html"));
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Welcome, " + encodedUserInput + "</h1>");
        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

